head.script:
scwin.onpageload = function () {
    document.getElementById("popup_status").innerText =
        "팝업 onpageload\n" +
        "key1='" + WebSquare.session.getAttribute("key1") + "'\n" +
        "key2='" + WebSquare.session.getAttribute("key2") + "'\n" +
        "key3='" + WebSquare.session.getAttribute("key3") + "'";
};

scwin.btn_removeSession_onclick = function () {
    WebSquare.session.removeSession();
    document.getElementById("popup_status").innerText =
        "팝업에서 removeSession() 호출 후\n" +
        "key1=" + WebSquare.session.getAttribute("key1") + "\n" +
        "key2=" + WebSquare.session.getAttribute("key2") + "\n" +
        "key3=" + WebSquare.session.getAttribute("key3") + "\n\n" +
        "→ 팝업을 닫고 메인 윈도우의 [메인 세션 확인] 버튼을 클릭하세요.";
};
